class Solution:
    def maxStability(self, n: int, edges: List[List[int]], k: int) -> int:
        import sys
        sys.setrecursionlimit(2000000)

        must_edges = []
        optional_edges = []
        for u, v, s, must in edges:
            if must == 1:
                must_edges.append((u, v, s))
            else:
                optional_edges.append((u, v, s))

        parent = list(range(n))
        rank = [0] * n

        def find(u):
            while parent[u] != u:
                parent[u] = parent[parent[u]]
                u = parent[u]
            return u

        def union(u, v):
            root_u = find(u)
            root_v = find(v)
            if root_u == root_v:
                return False
            if rank[root_u] > rank[root_v]:
                parent[root_v] = root_u
            else:
                parent[root_u] = root_v
                if rank[root_u] == rank[root_v]:
                    rank[root_v] += 1
            return True

        for u, v, s in must_edges:
            if not union(u, v):
                return -1

        components = set()
        for i in range(n):
            components.add(find(i))
        if len(components) > 1:
            return -1

        parent = list(range(n))
        rank = [0] * n

        for u, v, s in must_edges:
            union(u, v)

        optional_edges.sort(key=lambda x: -x[2])

        low = 0
        high = 0
        if optional_edges:
            high = max(s for u, v, s in optional_edges) * 2
        high = max(high, max(s for u, v, s in must_edges) if must_edges else 0)

        def is_possible(mid):
            parent_copy = parent[:]
            rank_copy = rank[:]

            def find_copy(u):
                while parent_copy[u] != u:
                    parent_copy[u] = parent_copy[parent_copy[u]]
                    u = parent_copy[u]
                return u

            def union_copy(u, v):
                root_u = find_copy(u)
                root_v = find_copy(v)
                if root_u == root_v:
                    return False
                if rank_copy[root_u] > rank_copy[root_v]:
                    parent_copy[root_v] = root_u
                else:
                    parent_copy[root_u] = root_copy[root_v]
                    if rank_copy[root_u] == rank_copy[root_v]:
                        rank_copy[root_v] += 1
                return True

            used_upgrades = 0
            for u, v, s in optional_edges:
                if find_copy(u) == find_copy(v):
                    continue
                if s >= mid:
                    union_copy(u, v)
                else:
                    if used_upgrades < k and 2 * s >= mid:
                        used_upgrades += 1
                        union_copy(u, v)
                    else:
                        pass

            roots = set()
            for i in range(n):
                roots.add(find_copy(i))
            return len(roots) == 1

        left = 0
        right = 0
        if optional_edges:
            right = max(s for u, v, s in optional_edges) * 2
        right = max(right, max(s for u, v, s in must_edges) if must_edges else 0)
        answer = -1

        while left <= right:
            mid = (left + right) // 2
            if is_possible(mid):
                answer = mid
                left = mid + 1
            else:
                right = mid - 1

        return answer
